{
  "mode": "method",
  "tests": [
    {
      "name": "valid_application_bangalore",
      "input": {
        "location": "Bangalore",
        "willing_to_relocate": false,
        "duration_weeks": 12,
        "working_hours": 8.5
      },
      "output": "eligible",
      "notes": "Valid application from a candidate based in Bangalore."
    },
    {
      "name": "valid_application_chennai",
      "input": {
        "location": "Chennai",
        "willing_to_relocate": false,
        "duration_weeks": 8,
        "working_hours": 8.5
      },
      "output": "eligible",
      "notes": "Valid application from a candidate based in Chennai."
    },
    {
      "name": "valid_application_relocation",
      "input": {
        "location": "Mumbai",
        "willing_to_relocate": true,
        "duration_weeks": 16,
        "working_hours": 8.5
      },
      "output": "eligible",
      "notes": "Candidate is willing to relocate to Bangalore or Chennai."
    },
    {
      "name": "invalid_application_duration_too_short",
      "input": {
        "location": "Bangalore",
        "willing_to_relocate": false,
        "duration_weeks": 2,
        "working_hours": 8.5
      },
      "output": "ineligible",
      "notes": "Duration is less than the minimum required (4 weeks)."
    },
    {
      "name": "invalid_application_duration_too_long",
      "input": {
        "location": "Chennai",
        "willing_to_relocate": false,
        "duration_weeks": 20,
        "working_hours": 8.5
      },
      "output": "ineligible",
      "notes": "Duration exceeds the maximum allowed (16 weeks)."
    },
    {
      "name": "invalid_application_working_hours",
      "input": {
        "location": "Bangalore",
        "willing_to_relocate": false,
        "duration_weeks": 12,
        "working_hours": 10
      },
      "output": "ineligible",
      "notes": "Working hours exceed the allowed daily limit."
    },
    {
      "name": "invalid_application_no_location",
      "input": {
        "location": "",
        "willing_to_relocate": false,
        "duration_weeks": 8,
        "working_hours": 8.5
      },
      "output": "ineligible",
      "notes": "Location must be specified."
    },
    {
      "name": "valid_application_minimum_duration",
      "input": {
        "location": "Bangalore",
        "willing_to_relocate": false,
        "duration_weeks": 4,
        "working_hours": 8.5
      },
      "output": "eligible",
      "notes": "Valid application with minimum duration."
    }
  ],
  "assumptions": "Candidates must meet location and duration requirements.",
  "notes": "Ensure to validate both location and duration criteria."
}
